import React from "react";
import Slider from "react-slick";

export default function SimpleSlider() {
  var settings = {
    dots: true,
    // infinite: true,
    speed: 500,
    slidesToShow: 5,
    slidesToScroll: 1
  };
  return (
    <Slider {...settings}>
        <img src="frontend\public\images\airpods.jpg" />
        <img src="frontend\public\images\airpods.jpg" />
    </Slider>
  );
}
